//------------------------------------------------------------------------------------------------------
// locator polynome roots search & error correction algorithm
//------------------------------------------------------------------------------------------------------

bch_eras_chieny_search
#(
  .m        ( m        ) ,
  .k_max    ( k_max    ) ,
  .d        ( d        ) ,
  .n        ( n        ) ,
  .irrpol   ( irrpol   )
)

  always_ff @(posedge iclk) begin
    if (iclkena) begin
      // Lextr use in col/row stages
      if (irow_mode) begin
        ostrb   <= vect_strb   [0];
        oLextr  <= vect_Lextr  [0];
        obitdat <= vect_bitdat [0];
        obiterr <= vect_biterr [0];
        //
        for (int i = 1; i < pDEC_NUM; i++) begin
          if (vect_val[i]) begin
            ostrb   <= vect_strb   [i];
            oLextr  <= vect_Lextr  [i];
            obitdat <= vect_bitdat [i];
            obiterr <= vect_biterr [i];
          end
        end
      end
      else begin
        ostrb   <= istrb[0];
        oLextr  <= iLextr;
        obitdat <= ibitdat;
        obiterr <= ibiterr;
      end
    end
  end

endmodule

always_ff @(posedge iclk) begin
  if (iclkena) begin
    strb  <= istrb;
    smask <= ismask;
    for (int i = 0; i < pDEC_NUM; i++) begin
      if (ismask[i]) begin
        ch_hd[i] <= 1'b0;
        Lapri[i] <= -(2**(pLLR_W-1)-1); // strongest zero for shortened
      end
      else begin
        ch_hd[i] <= (iLLR[i] >= 0);
        Lapri[i] <=  iLLR[i] + do_scale(iLextr[i], ialpha);
      end
    end
  end
end

